func TestNetworkSim_SplitBrainRecovery(t *testing.T) {
	ns := NewNetworkSim(42)
	// Create two groups: {n0,n1} and {n2,n3}
	for i := 0; i < 4; i++ {
		ns.AddNode(fmt.Sprintf("n%d", i), 2)
