	}
	return result
}

// Apply merges a set of remote entries into the local store.
// Only entries with a higher version than the local entry are accepted. If
// versions tie, tombstones win over live entries.
// Returns the number of entries that were actually applied.
func (s *StateStore) Apply(entries []*StateEntry) int {
	s.mu.Lock()
	defer s.mu.Unlock()
	applied := 0
	for _, remote := range entries {
		local, ok := s.entries[remote.Key]
		if !ok || isRemoteNewer(remote.Version, remote.Tombstone, local.Version, local.Tombstone) {
			cp := *remote
