// RunMerkleSyncRound performs merkle-based anti-entropy between random pairs.
func (ns *NetworkSim) RunMerkleSyncRound() int {
	ns.mu.Lock()
	defer ns.mu.Unlock()
	ns.clock++

	synced := 0
	peerList := ns.peerList()
	if len(peerList) < 2 {
		return 0
	}

	msel := gossip.NewRandomPeerSelector(ns.rng.Int63())
	for _, nodeID := range peerList {
		store := ns.stores[nodeID]
		// Pick a random peer
		peers := msel.SelectPeers(peerList, nodeID, 1)
		if len(peers) == 0 {
			continue
		}
		peerID := peers[0]
		if ns.isPartitioned(nodeID, peerID) {
			continue
		}

		peerStore, ok := ns.stores[peerID]
		if !ok {
			continue
		}

		// Build merkle trees from both stores
		localTree := storeToTree(store)
		remoteTree := storeToTree(peerStore)
		diff := merkle.FastDiff(localTree, remoteTree)

		// Sync differing keys using Apply to preserve versions
		for _, key := range diff.OnlyRemote {
			e, ok := peerStore.GetEntry(key)
			if ok {
				synced += store.Apply([]*gossip.StateEntry{e})
			}
		}
		for _, key := range diff.OnlyLocal {
			e, ok := store.GetEntry(key)
			if ok {
				synced += peerStore.Apply([]*gossip.StateEntry{e})
			}
		}
		for _, key := range diff.Different {
			le, _ := store.GetEntry(key)
			re, _ := peerStore.GetEntry(key)
			if le != nil && re != nil {
				synced += peerStore.Apply([]*gossip.StateEntry{le})
				synced += store.Apply([]*gossip.StateEntry{re})
			}
		}

		ns.recordEvent(Event{
			Time:    ns.clock,
			Type:    EventMerkleDiff,
			Source:  nodeID,
			Target:  peerID,
			Payload: diff.TotalDiffs(),
		})
	}
	return synced
}

func storeToTree(store *gossip.StateStore) *merkle.Tree {
	tree := merkle.NewTree()
	digest := store.Digest()
	entries := make(map[string][]byte, len(digest.Entries))
	for key := range digest.Entries {
		entry, ok := store.GetEntry(key)
		if ok {
			entries[key] = merkleEntryValue(entry)
		}
	}
	tree.PutBatch(entries)
	return tree
}

func merkleEntryValue(entry *gossip.StateEntry) []byte {
	value := make([]byte, 9+len(entry.Value))
	binary.BigEndian.PutUint64(value[:8], entry.Version)
	if entry.Tombstone {
		value[8] = 1
	}
	copy(value[9:], entry.Value)
	return value
}

func (ns *NetworkSim) peerList() []string {
	list := make([]string, 0, len(ns.nodes))
	for id := range ns.nodes {
		list = append(list, id)
	}
	sort.Strings(list)
	return list
}

// Converged checks if all nodes have the same state hash.
func (ns *NetworkSim) Converged() bool {
	ns.mu.Lock()
	defer ns.mu.Unlock()
	var firstHash [32]byte
	first := true
	for _, store := range ns.stores {
		h := store.Hash()
		if first {
			firstHash = h
			first = false
		} else if h != firstHash {
			return false
		}
	}
	return true
}

