func TestNetworkSim_MerkleSyncBulkDeletesConverge(t *testing.T) {
	ns := NewNetworkSim(99)
	nodeIDs := []string{"n0", "n1", "n2", "n3", "n4"}
	for _, nodeID := range nodeIDs {
		ns.AddNode(nodeID, 2)
	}

	keys := make([]string, 20)
	for i := range keys {
		keys[i] = fmt.Sprintf("bulk-%02d", i)
		ns.GetStore("n0").Put(keys[i], []byte(fmt.Sprintf("value-%02d", i)))
	}
	runMerkleUntilConverged(t, ns, 200)

	var maxDeleteVersion uint64
	for _, key := range keys {
		version := ns.GetStore("n0").Delete(key)
		if version > maxDeleteVersion {
			maxDeleteVersion = version
		}
	}

	runMerkleUntilConverged(t, ns, 300)
	assertMerkleDeleted(t, ns, nodeIDs, keys, 0)
	for _, nodeID := range nodeIDs {
		if ns.GetStore(nodeID).Len() != 0 {
			t.Fatalf("node %s should have no live entries after bulk deletes", nodeID)
		}
	}
	if maxDeleteVersion == 0 {
		t.Fatal("expected delete versions to be recorded")
	}
}

func runMerkleUntilConverged(t *testing.T, ns *NetworkSim, maxRounds int) {
	t.Helper()
	for round := 0; round < maxRounds; round++ {
		ns.RunMerkleSyncRound()
		if ns.Converged() {
			return
		}
	}
	t.Fatalf("merkle sync did not converge in %d rounds", maxRounds)
}

func assertMerkleDeleted(t *testing.T, ns *NetworkSim, nodeIDs, keys []string, wantVersion uint64) {
	t.Helper()
	for _, nodeID := range nodeIDs {
		store := ns.GetStore(nodeID)
		for _, key := range keys {
			if _, ok := store.Get(key); ok {
				t.Fatalf("node %s should not return deleted key %s", nodeID, key)
			}
			entry, ok := store.GetEntry(key)
			if !ok {
				t.Fatalf("node %s missing tombstone for key %s", nodeID, key)
			}
			if !entry.Tombstone {
				t.Fatalf("node %s has live entry for deleted key %s", nodeID, key)
			}
			if wantVersion != 0 && entry.Version != wantVersion {
				t.Fatalf("node %s tombstone for key %s has version %d, want %d", nodeID, key, entry.Version, wantVersion)
			}
		}
	}
}

